import java.util.*;
public class ListParam {
    static void addItem(List<String> list) {
        list = new ArrayList<>();    // reassigns local parameter
        list.add("new item");
    }
    public static void main(String[] args) {
        List<String> myList = new ArrayList<>();
        myList.add("original");
        addItem(myList);
        System.out.println(myList);   // [original]
    }
}
